Here's how you can modify your `DataCache` class to implement an LRU eviction policy:

```python
import time
import collections

class DataCache:
    _instance = None
    _cache = {}
    _max_size = 100  # Define the maximum cache size

    @classmethod
    def get_instance(cls):
        if cls._instance is None:
            cls._instance = cls()
        return cls._instance

    def store(self, key, data):
        self._cache[key] = {
            'data': data,
            'timestamp': time.time(),
            'access_count': 0,
            'access_time': time.time()
        }
        if len(self._cache) >= self._max_size:
            # Implement LRU eviction
            least_recently_used = min(self._cache.items(), key=lambda x: x[1]['access_time'])
            del self._cache[least_recently_used[0]]

    def get(self, key):
        if key in self._cache:
            self._cache[key]['access_count'] += 1
            self._cache[key]['access_time'] = time.time()
            return self._cache[key]['data']
        return None

@app.route('/api/reports/<report_id>')
