from threading import Lock

app = Flask(__name__)
socketio = SocketIO(app)

# Shared state for the text document
document_lock = Lock()
document = ""

# Helper function to handle incoming changes
def handle_text_change(message):
    with document_lock:
        document = message['text']
        emit('text-changed', document=document)

